import React, { useEffect, useState } from 'react';
import axios from '../api/axiosConfig';

function DashboardPage({ user }) {
  const [complaints, setComplaints] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!user) return;
    const fetchComplaints = async () => {
      setLoading(true);
      setError('');
      try {
        const response = await axios.get('/complaints');
        setComplaints(response.data);
      } catch (err) {
        setError('Unable to load your complaints');
      } finally {
        setLoading(false);
      }
    };
    fetchComplaints();
  }, [user]);

  if (!user) {
    return <div className="card">Please login to view your dashboard.</div>;
  }

  return (
    <div className="card">
      <h2>Welcome, {user.name}</h2>
      <p>Use the menu to submit a complaint or check the history.</p>
      <div className="summary-row">
        <div className="summary-box">
          <strong>Total complaints</strong>
          <span>{complaints.length}</span>
        </div>
      </div>
      <h3>Your recent complaints</h3>
      {loading && <div className="info-box">Loading complaints...</div>}
      {error && <div className="error-box">{error}</div>}
      {!loading && complaints.length === 0 && <p>No complaints found yet.</p>}
      <div className="table-scroll">
        <table>
          <thead>
            <tr>
              <th>Title</th>
              <th>Category</th>
              <th>Status</th>
              <th>Date</th>
            </tr>
          </thead>
          <tbody>
            {complaints.map((item) => (
              <tr key={item._id}>
                <td>{item.title}</td>
                <td>{item.category}</td>
                <td>{item.status}</td>
                <td>{new Date(item.createdAt).toLocaleDateString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default DashboardPage;
